section.script:
                document.addEventListener('DOMContentLoaded', function() {
                    const tabButtons = document.querySelectorAll('.tire-brand-tab');
                    const productsContainer = document.getElementById('tire-products-container');

                    // Add click handlers to tabs
                    tabButtons.forEach((tab) => {
                        tab.addEventListener('click', function(e) {
                            e.preventDefault();

                            // Remove active from all tabs
                            tabButtons.forEach(t => {
                                t.classList.remove('active');
                                t.style.color = '#999';
                                t.style.borderBottomColor = 'transparent';
                            });

                            // Set active on clicked tab
                            this.classList.add('active');
                            this.style.color = '#FF0000';
                            this.style.borderBottomColor = '#FF0000';

                            // Get products from data attribute
                            const productsJson = this.getAttribute('data-seller-products');
                            const products = JSON.parse(productsJson);

                            // Clear container
                            productsContainer.innerHTML = '';

                            // Display products
                            if (products.length > 0) {
                                products.forEach(product => {
                                    const col = document.createElement('div');
                                    col.className = 'col-lg-4 col-md-6 col-sm-12';

                                    col.innerHTML = `



${product.categ}

${product.name}

${Math.round(product.price)} $

${product.categ}




                            View Details

                                    `;

                                    productsContainer.appendChild(col);
                                });
                            } else {
                                productsContainer.innerHTML = '

No products available for this brand';
                            }
                        });
                    });
                });

template.script:
document.addEventListener('DOMContentLoaded', function() {
    // Vehicle category click handler
    document.querySelectorAll('.vehicle-category').forEach(category => {
        category.addEventListener('click', function() {
            console.log('Vehicle category clicked');
            // Add search functionality here
        });
    });

    // Search button handler
    document.querySelector('.finder-btn').addEventListener('click', function() {
        const year = document.querySelectorAll('.finder-select')[0].value;
        const make = document.querySelectorAll('.finder-select')[1].value;
        const model = document.querySelectorAll('.finder-select')[2].value;
        const engine = document.querySelectorAll('.finder-select')[3].value;

        console.log('Search:', { year, make, model, engine });

        // Redirect to shop with filters
        if (year || make || model || engine) {
            const params = new URLSearchParams();
            if (year) params.append('year', year);
            if (make) params.append('make', make);
            if (model) params.append('model', model);
            if (engine) params.append('engine', engine);

            window.location.href = '/shop?' + params.toString();
        }
    });
});

